scwin.f_changeRadioVal = function (inputClsCd) {
  // 01: 수탁자 매입거래처 / 02: 수탁자 기준
  if (inputClsCd == "01") {
    udc_topGrBtn.setGridId("gr_trusteeClntCost");
    udc_bottomGrdBtn.setGridId("gr_trusteeClntCost");

    /*차량번호 팝업 숨김*/
    cartitle.visible(false);
    carlabel.visible(false);
    td_clnt_title.setValue("매입거래처");
    grid_title.setValue("수탁자 매입거래처 기준");
    gr_trusteeClntCost.setStyle("display", "");
    gr_trusteeCost.setStyle("display", "none"); // 그리드 숨기기

    udc_comCode_clnt.show(); // 수탁자 매입거래처 보여주기
    udc_comCode_crn.hide(); //수탁자기준 udc 숨기기
  } else if (inputClsCd == "02") {
    udc_topGrBtn.setGridId("gr_trusteeCost");
    udc_bottomGrdBtn.setGridId("gr_trusteeCost");
    cartitle.visible(true);
    carlabel.visible(true);
    td_clnt_title.setValue("매입거래처 수탁자");
    grid_title.setValue("수탁자 기준");
    gr_trusteeClntCost.setStyle("display", "none"); // 그리드 숨기기
    gr_trusteeCost.setStyle("display", ""); // 그리드 보이기

    udc_comCode_clnt.hide(); // 수탁자 매입거래처 udc
    udc_comCode_crn.show(); //수탁자기준 udc
  }
};
scwin.onpageload = function () {
  // 매입거래처 수탁자 기준 조회
  let params = $c.data.getParameter($p);
  let outbrCo = params.outbrCo == null ? "" : params.outbrCo;
  let outbrNo = params.outbrNo == null ? "" : params.outbrNo;
  let vehclNo = params.vehclNo == null ? "" : params.vehclNo;
  let vehclNm = params.vehclNm == null ? "" : params.vehclNm;
  let regBran = params.regBran == null ? "" : params.regBran;
  let regBranCd = params.regBranCd == null ? "" : params.regBranCd;
  scwin.retrieveType = params.type == null ? "" : request.type;

  // type="retrieve" : 다른 페이지에서 넘어온 데이터 포함 조회(수탁자 기준 조회)
  if (scwin.retrieveType === "retrieve") {
    // 수탁자 기준
    scwin.f_changeRadioVal("02");

    // 파라미터 값 셋팅
    ed_lobranCd.setValue(regBranCd); // 청구지점
    ed_lobranNm.setValue(regBran);
    ed_vehclShortCd.setValue(vehclNo); // 차량번호
    ed_vehclNo.setValue(vehclNm);
    ed_clntNo.setValue(outbrCo); // 매입거래처 수탁자
    ed_clntNm.setValue(outbrNo);
    ed_ctrtDtMm.setValue(scwin.strCurYyMm);
  } else {
    // 수탁자 매입거래처
    scwin.f_changeRadioVal("01");
    $c.gus.cfDisableBtnOnly($p, [btn_save]);
  }

  //공통코드 적용
  const codeOptions = [{
    grpCd: "FS900",
    compID: "gr_trusteeCost:costItemCd, gr_trusteeClntCost:costItemCd"
  }];
  $c.data.setCommonCode($p, codeOptions);
  scwin.init();

  // 달력 버튼 포커스 방지
  setTimeout(function () {
    document.querySelectorAll('.w2inputCalendar_div_img button').forEach(function (btn) {
      btn.tabIndex = -1;
    });
  }, 0);
};
