//-------------------------------------------------------------------------
// 그리드의 차량번호 PopUp (해당 row Index, changeValue)
//-------------------------------------------------------------------------	
scwin.f_gridVechlPop = async function (row, shortCd) {
  if (scwin.isNonPop) {
    scwin.isNonPop = false;
    return;
  }
  let pCode = "";
  let pName = "";
  if (shortCd == null) {
    pCode = ds_TrusteeCost.getCellAllData(row, "vehclShortCd");
    pName = ds_TrusteeCost.getCellData(row, "vehclNo");
  } else {
    pCode = shortCd.trim();
    pName = "";
  }
  let data = {
    param1: ed_ctrtDtMm.getValue(),
    param2: pCode,
    // 차량 단축 코드
    param3: pName // 차량 번호 이름
  };
  let opts = {
    id: "searchpop",
    popupName: "수탁자 차량 계약정보 조회 팝업",
    modal: true,
    width: 800,
    // 가로 크기 (픽셀)
    height: 600,
    // 세로 크기 (픽셀)
    type: "",
    title: "Win pop"
  };
  let rtnList = await $c.win.openPopup($p, "/ui/ds/fs/consignmgnt/fs_402_01_04p.xml", opts, data);
  //console.log("차량조회 팝업 결과: " + JSON.stringify(rtnList));

  let vehclShortCd = rtnList ? rtnList.vehclShortCd : ""; // 단축번호
  let vehclNo = rtnList ? rtnList.vehclNo : ""; // 차량번호
  let drvNm = rtnList ? rtnList.clntNm : ""; // 위수탁자명
  let ctrtNo = rtnList ? rtnList.ctrtNo : ""; // 계약번호
  let eqCd = rtnList ? rtnList.eqCd : ""; // 장비코드
  let costItemCd = rtnList ? rtnList.costItemCd : ""; // 비용항목 코드

  ds_TrusteeCost.setCellData(row, "vehclShortCd", vehclShortCd);
  ds_TrusteeCost.setCellData(row, "vehclNo", vehclNo);
  if (!$c.util.isEmpty($p, drvNm)) ds_TrusteeCost.setCellData(row, "drvNm", drvNm);
  ds_TrusteeCost.setCellData(row, "ctrtNo", ctrtNo);
  ds_TrusteeCost.setCellData(row, "eqCd", eqCd);
  if (!$c.util.isEmpty($p, vehclShortCd)) {
    // 단축번호 없으면, 비용항목도 빈값
    ds_TrusteeCost.setCellData(row, "costItemCd", ed_costItemCd.getValue());
  } else {
    ds_TrusteeCost.setCellData(row, "costItemCd", "");
  }
};

