//매입거래처 저장callback

scwin.sbm_save_submitdone = async function (e) {
  //sucess/fail 여부 if 처리 add
  // responseJSON에서 resultDataSet 추출
  var resultDataSet = e.responseJSON.resultDataSet;
  if (!resultDataSet || resultDataSet.length === 0) {
    return;
  }

  // 첫번째 행 = Result (성공/실패 여부)
  var result = resultDataSet[0];
  if (result.Msg === "SUCC") {
    // 성공
    await $c.gus.cfAlertMsg($p, MSG_CM_INF_001);
    scwin.f_Retrieve(); // 재조회
  }
};

//수탁자기준 저장callback

scwin.sbm_save2_submitdone = async function (e) {
  //sucess/fail 여부 if 처리 add

  // responseJSON에서 resultDataSet 추출
  var resultDataSet = e.responseJSON.resultDataSet;
  if (!resultDataSet || resultDataSet.length === 0) {
    return;
  }

  // 첫번째 행 = Result (성공/실패 여부)
  var result = resultDataSet[0];
  if (result.Msg === "SUCC") {
    // 성공
    await $c.gus.cfAlertMsg($p, MSG_CM_INF_001);
    scwin.f_Retrieve(); // 재조회
  }
};

// 사업자번호 표시 포맷 적용 
scwin.f_formatCrn = function (value) {
  if (!value) return "";
  var str = value.toString();
  if (str.length < 10) return str;
  return str.substring(0, 3) + "-" + str.substring(3, 5) + "-" + str.substring(5, 10);
};

// "01": 수탁자 매입거래처 기준 
scwin.gr_trusteeClntCost_onviewchange = function (info) {
  let rowIdx = info.rowIndex;
  if (info.colId === "vehclShortCd") {
    scwin.f_gridVechlPop(info.rowIndex, info.newValue);
  } else if (info.colId === "spplyAmt") {
    let spplyAmt = parseInt(info.newValue); // 공급금액
    let vatAmt = 0; // 세액
    let totAmt = 0; // 합계

    vatAmt = 0; //Math.floor(spplyAmt / 10);
    totAmt = spplyAmt + vatAmt;
    ds_TrusteeCost.setCellData(rowIdx, "vatAmt", vatAmt);
    ds_TrusteeCost.setCellData(rowIdx, "totAmt", totAmt);
    ds_TrusteeCost.setCellData(rowIdx, "adjmAmt", totAmt);
  } else if (info.colId === "vatAmt") {
    let spplyAmt = parseInt(ds_TrusteeCost.getCellData(rowIdx, "spplyAmt")); // 공급금액
    let vatAmt = parseInt(info.newValue); // 세액
    let totAmt = 0; // 합계

    totAmt = spplyAmt + vatAmt;
    ds_TrusteeCost.setCellData(rowIdx, "totAmt", totAmt);
    ds_TrusteeCost.setCellData(rowIdx, "adjmAmt", totAmt);
  }
};
scwin.gr_trusteeCost_onviewchange = function (info) {
  // "상호" 없어지면, 그에따른 사업자번호, 거래처번호, 비용항목도 빈값
  let rowIdx = info.rowIndex;
  if (info.colId === "clntNm") {
    if ($c.util.isEmpty($p, info.newValue)) {
      ds_TrusteeCost2.setCellData(rowIdx, "crn", "");
      ds_TrusteeCost2.setCellData(rowIdx, "clntNo", "");
      ds_TrusteeCost2.setCellData(rowIdx, "costItemCd", "");
    } else {
      scwin.f_gridCrnPop(rowIdx);
    }
  } else if (info.colId === "spplyAmt") {
    let spplyAmt = parseInt(info.newValue); // 공급금액
    let vatAmt = 0; // 세액
    let totAmt = 0; // 합계

    vatAmt = 0; //Math.floor(spplyAmt / 10);
    totAmt = spplyAmt + vatAmt;
    ds_TrusteeCost2.setCellData(rowIdx, "vatAmt", vatAmt);
    ds_TrusteeCost2.setCellData(rowIdx, "totAmt", totAmt);
    ds_TrusteeCost2.setCellData(rowIdx, "adjmAmt", totAmt);
  } else if (info.colId === "vatAmt") {
    let spplyAmt = parseInt(ds_TrusteeCost2.getCellData(rowIdx, "spplyAmt")); // 공급금액
    let vatAmt = parseInt(info.newValue); // 세액
    let totAmt = 0; // 합계

    totAmt = spplyAmt + vatAmt;
    ds_TrusteeCost2.setCellData(rowIdx, "totAmt", totAmt);
    ds_TrusteeCost2.setCellData(rowIdx, "adjmAmt", totAmt);
  }
};

